public static int max(int[] a) {
    if (a == null || a.length == 0) {
        throw new IllegalArgumentException("empty array");
    }
    int max = a[0];
    for (int i = 1; i < a.length; i++) {
        if (a[i] > max) {
            max = a[i];
        }
    }
    return max;
}

public static ArrayList<Integer> positives(int[] a) {
    ArrayList<Integer> list = new ArrayList<>();
    for (int v : a) {
        if (v > 0) {
            list.add(v); // autoboxing
        }
    }
    return list;
}

public static void transposeInPlace(int[][] m) {
    int n = m.length;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int tmp = m[i][j];
            m[i][j] = m[j][i];
            m[j][i] = tmp;
        }
    }
}
